import{_ as t,c as o,o as r,ag as a}from"./chunks/framework.Bw-5EFTY.js";const m=JSON.parse('{"title":"Remote Server Core Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/agent-remote-server-core/docs/SPEC.md","filePath":"packages/agent-remote-server-core/docs/SPEC.md"}'),i={name:"packages/agent-remote-server-core/docs/SPEC.md"};function n(s,e,c,d,l,p){return r(),o("div",null,e[0]||(e[0]=[a('<h1 id="remote-server-core-specification" tabindex="-1">Remote Server Core Specification <a class="header-anchor" href="#remote-server-core-specification" aria-label="Permalink to &quot;Remote Server Core Specification&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>Owns reusable Remote API server route registration and OpenAPI documentation for Robota. Provides a single <code>registerRemoteServerRoutes</code> function that mounts <code>RemoteServer</code> from <code>@robota-sdk/agent-remote/server</code> onto an Express application, configures Swagger UI, and returns a runtime status handle.</p><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><ul><li>Does not own remote client contracts or transport types; those belong to <code>@robota-sdk/agent-remote</code>.</li><li>Does not own <code>RemoteServer</code> implementation; imports from <code>@robota-sdk/agent-remote/server</code>.</li><li>Does not own AI provider contracts (<code>IAIProvider</code>); imports from <code>@robota-sdk/agent-core</code>.</li><li>Does not own app-specific deployment, middleware, or environment configuration; that belongs to consumer apps (<code>apps/agent-server</code>).</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>Thin composition layer. <code>registerRemoteServerRoutes</code> accepts an Express app, a provider map, and configuration options. It creates a <code>RemoteServer</code> instance, mounts its router at a configurable base path (default <code>/api/v1/remote</code>), and optionally serves Swagger UI at <code>/docs/remote</code> with the bundled OpenAPI document. Returns <code>IRemoteServerRuntime</code> for status queries.</p><h2 id="type-ownership" tabindex="-1">Type Ownership <a class="header-anchor" href="#type-ownership" aria-label="Permalink to &quot;Type Ownership&quot;">​</a></h2><p>This package is SSOT for:</p><ul><li><code>IRegisterRemoteServerRoutesOptions</code> -- options for route registration (app, providers, basePath, apiDocsEnabled, logger).</li><li><code>IRemoteServerRuntime</code> -- runtime handle with <code>getStatus()</code>.</li><li><code>IRemoteServerLogger</code> -- logger interface required by the registration function.</li><li><code>REMOTE_OPENAPI_DOCUMENT</code> -- OpenAPI 3.0.3 specification object for the Remote API.</li></ul><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Description</th></tr></thead><tbody><tr><td><code>registerRemoteServerRoutes</code></td><td>function</td><td>Mounts remote server routes and Swagger UI on an Express app</td></tr><tr><td><code>IRegisterRemoteServerRoutesOptions</code></td><td>interface</td><td>Configuration for route registration</td></tr><tr><td><code>IRemoteServerRuntime</code></td><td>interface</td><td>Runtime status handle</td></tr><tr><td><code>IRemoteServerLogger</code></td><td>interface</td><td>Logger contract for server operations</td></tr><tr><td><code>REMOTE_OPENAPI_DOCUMENT</code></td><td>const</td><td>OpenAPI specification object</td></tr></tbody></table><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><ul><li><code>IRemoteServerLogger</code> -- consumers inject their own logger implementation.</li><li><code>basePath</code> option -- consumers can mount routes at a custom path prefix.</li><li><code>apiDocsEnabled</code> option -- toggle Swagger UI exposure.</li></ul><h2 id="error-taxonomy" tabindex="-1">Error Taxonomy <a class="header-anchor" href="#error-taxonomy" aria-label="Permalink to &quot;Error Taxonomy&quot;">​</a></h2><p>This package does not define its own error types. Errors propagate from:</p><ul><li><code>RemoteServer.initialize()</code> failure -- logged via the injected logger; the promise rejection is caught internally.</li><li>Express middleware errors -- handled by the consumer app&#39;s error middleware.</li></ul><h2 id="test-strategy" tabindex="-1">Test Strategy <a class="header-anchor" href="#test-strategy" aria-label="Permalink to &quot;Test Strategy&quot;">​</a></h2><ul><li><strong>1 test file exists</strong>: <code>src/remote-server-routes.test.ts</code> (165 lines) covering route registration behavior.</li><li>The package has minimal logic (route wiring only), making integration testing at the <code>apps/agent-server</code> level more appropriate.</li><li>Recommended: additional smoke tests verifying Swagger UI mount and logger injection.</li></ul>',19)]))}const h=t(i,[["render",n]]);export{m as __pageData,h as default};
